+#[test]
+fn setmode_rejects_tracked_unterminated_mode() {
+    unsafe {
+        let raw = malloc_unterminated(b"u+x");
+        *__errno_location() = 0;
+
+        let bbox = setmode(raw);
+
+        frankenlibc_abi::malloc_abi::free(raw.cast());
+        assert!(bbox.is_null());
+        assert_eq!(*__errno_location(), libc::EINVAL);
+    }
